from flask import Flask, request, redirect, url_for, session, abort, render_template_string
from functools import wraps
from urllib.parse import urlparse

app = Flask(__name__)
app.secret_key = 'your-secret-key-change-in-production'

# --- Configuration ---

# Allowlist of permitted redirect destinations (route identifiers)
ALLOWED_REDIRECT_ROUTES = {
    'dashboard',
    'profile',
    'settings',
    'home',
    'orders',
    'reports',
}

# Mapping of route identifiers to actual URL paths (server-side route mapping)
ROUTE_MAP = {
    'dashboard': '/dashboard',
    'profile': '/profile',
    'settings': '/settings',
    'home': '/',
    'orders': '/orders',
    'reports': '/reports',
}

# Default redirect destination after login
DEFAULT_REDIRECT = 'dashboard'

# Simulated user database
USERS = {
    'admin': 'password123',
    'user1': 'mypassword',
}


# --- Helper Functions ---

def validate_redirect_destination(destination):
    """
    Validate that the redirect destination is allowed.
    Uses server-side route identifiers instead of arbitrary URLs.
    Returns the safe URL path or None if invalid.
    """
    if not destination:
        return None

    # Only allow known route identifiers (not arbitrary URLs)
    if destination in ALLOWED_REDIRECT_ROUTES and destination in ROUTE_MAP:
        return ROUTE_MAP[destination]

    return None


def validate_redirect_url(url):
    """
    If a URL is provided directly, validate it against the allowlist.
    Rejects external URLs, open redirects, and non-allowlisted paths.
    """
    if not url:
        return None

    parsed = urlparse(url)

    # Reject any URL with a scheme or netloc (external redirect)
    if parsed.scheme and parsed.scheme not in ('', 'http', 'https'):
        return None

    if parsed.netloc:
        return None

    # Reject URLs that try to bypass with protocol-relative URLs
    if url.startswith('//'):
        return None

    # Reject URLs with backslashes (common bypass technique)
    if '\\' in url:
        return None

    # Only allow paths that are in our known route map
    clean_path = parsed.path.rstrip('/')
    if not clean_path:
        clean_path = '/'

    allowed_paths = set(ROUTE_MAP.values())
    if clean_path in allowed_paths:
        return clean_path

    return None


def get_safe_redirect(route_id=None, url=None):
    """
    Get a safe redirect URL. Prefers route identifiers over raw URLs.
    Falls back to default redirect if destination is invalid.
    """
    # First, try route identifier (preferred method)
    if route_id:
        safe_url = validate_redirect_destination(route_id)
        if safe_url:
            return safe_url

    # Fallback: try validating a URL against allowlist
    if url:
        safe_url = validate_redirect_url(url)
        if safe_url:
            return safe_url

    # Default safe redirect
    return ROUTE_MAP[DEFAULT_REDIRECT]


def login_required(f):
    """Decorator to require authentication for a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            # Store the intended destination as a route identifier
            # Determine route ID from the current endpoint
            intended_route = request.endpoint
            if intended_route in ALLOWED_REDIRECT_ROUTES:
                return redirect(url_for('login', next_route=intended_route))
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


# --- Login/Logout Logic ---

def authenticate_user(username, password):
    """Simulate user authentication."""
    return USERS.get(username) == password


def perform_login_redirect(username):
    """
    Handle the redirect after successful authentication.
    Uses allowlisted route identifiers for safe redirection.
    """
    session['user'] = username

    # Get the intended destination from the request
    # Prefer route identifier over raw URL
    next_route = request.args.get('next_route') or request.form.get('next_route')
    next_url = request.args.get('next_url') or request.form.get('next_url')

    safe_redirect_url = get_safe_redirect(route_id=next_route, url=next_url)

    print(f"[LOGIN] User '{username}' authenticated. Redirecting to: {safe_redirect_url}")
    return redirect(safe_redirect_url)


