# --- Routes ---

@app.route('/login', methods=['GET', 'POST'])
def login():
    """Login route with safe redirect handling."""
    # If already logged in, redirect to intended destination or default
    if 'user' in session:
        next_route = request.args.get('next_route')
        safe_url = get_safe_redirect(route_id=next_route)
        return redirect(safe_url)

    error = None

    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')

        if authenticate_user(username, password):
            return perform_login_redirect(username)
        else:
            error = 'Invalid username or password.'

    # Pass the next_route to the template for the hidden form field
    next_route = request.args.get('next_route', '')
    next_url = request.args.get('next_url', '')

    return render_template_string(
        LOGIN_TEMPLATE,
        error=error,
        next_route=next_route,
        next_url=next_url
    )


@app.route('/logout')
def logout():
    """Logout and redirect to login page."""
    session.pop('user', None)
    return redirect(url_for('login'))


